sp_widget.client_script:
function($scope, spUtil) {
    var c = this;
    c.currentPage = 1;
    c.pageSize = 5;
    c.filter = 'pending';
    c.showModal = false;
    c.activeRejectId = '';

    c.setFilter = function(val) {
        c.filter = val;
        c.server.get({action: 'fetch', filter: c.filter}).then(function(r) {
            c.data.approvals = r.data.approvals;
        });
    };

    c.updateSearch = function() {
        c.server.get({action: 'fetch', filter: c.filter, searchQuery: c.searchQuery}).then(function(r) {
            c.data.approvals = r.data.approvals;
        });
    };

    c.approve = function(id) {
        c.server.get({action: 'approve', targetId: id}).then(function() {
            spUtil.addInfoMessage("Request Approved");
            c.setFilter(c.filter);
        });
    };

    c.openRejectModal = function(id) {
        c.activeRejectId = id;
        c.rejectComment = '';
        c.showModal = true;
    };

    c.confirmReject = function() {
        c.server.get({
            action: 'reject', 
            targetId: c.activeRejectId, 
            comment: c.rejectComment
        }).then(function() {
            c.showModal = false;
            spUtil.addErrorMessage("Request Rejected");
            c.setFilter(c.filter);
        });
    };
}

sp_widget.css:
/* containr and panel */
.panel {
  border: none;
  border-radius: 12px;
  box-shadow: 0 4px 20px rgba(0, 0, 0, 0.08);
  overflow: hidden;
  background-color: #ffffff;
}

.panel-heading {
  background-color: #f8fafc;
  border-bottom: 1px solid #e2e8f0;
  padding: 20px;
}

.panel-heading h4 {
  color: #1e293b;
  font-weight: 700;
  margin: 0;
  letter-spacing: -0.5px;
}

/* serach bar */
.form-control {
  border-radius: 8px;
  border: 1px solid #cbd5e1;
  padding: 10px 15px;
  transition: all 0.3s ease;
}

.form-control:focus {
  border-color: #3b82f6;
  box-shadow: 0 0 0 3px rgba(59, 130, 246, 0.1);
}

/* Tthe tabs */
.nav-tabs {
  border-bottom: 1px solid #e2e8f0;
  background: #f8fafc;
  padding: 0 10px;
}

.nav-tabs > li > a {
  border: none;
  color: #64748b;
  font-weight: 600;
  padding: 15px 25px;
  transition: color 0.3s;
}

.nav-tabs > li.active > a, 
.nav-tabs > li.active > a:hover {
  border: none;
  border-bottom: 3px solid #3b82f6;
  color: #3b82f6;
  background: transparent;
}

/* table */
.custom-table {
  margin-bottom: 0;
}

.custom-table thead th {
  background-color: #ffffff;
  color: #94a3b8;
  font-size: 12px;
  text-transform: uppercase;
  letter-spacing: 1px;
  font-weight: 600;
  padding: 15px 20px;
  border-bottom: 1px solid #f1f5f9;
}

.custom-table tbody td {
  padding: 18px 20px;
  vertical-align: middle;
  color: #334155;
  border-bottom: 1px solid #f1f5f9;
}

.custom-table tbody tr:hover {
  background-color: #f8fafc;
}

/* status */
.label {
  padding: 6px 12px;
  border-radius: 20px;
  font-weight: 500;
  font-size: 11px;
}

.label-warning { background-color: #fef3c7; color: #92400e; } /* Requested */
.label-success { background-color: #dcfce7; color: #166534; } /* Approved */
.label-danger  { background-color: #fee2e2; color: #991b1b; } /* Rejected */

/* btn */
.btn {
  border-radius: 8px;
  font-weight: 600;
  padding: 8px 16px;
  transition: transform 0.1s ease;
}

.btn:active { transform: scale(0.95); }

.btn-success { background-color: #10b981; border: none; }
.btn-danger  { background-color: #ef4444; border: none; }

/* paginationr */
.panel-footer {
  background-color: #ffffff;
  border-top: 1px solid #f1f5f9;
  padding: 15px;
  color: #64748b;
}

/* modal  */
.custom-modal-overlay {
  position: fixed; 
  top: 0; left: 0; width: 100%; height: 100%;
  background: rgba(15, 23, 42, 0.6); 
  backdrop-filter: blur(4px);
  z-index: 9999; 
  display: flex;
  justify-content: center; 
  align-items: center;
  animation: fadeIn 0.2s ease-out;
}

.custom-modal {
  background: #ffffff; 
  padding: 30px; 
  border-radius: 16px; 
  width: 100%;
  max-width: 450px;
  box-shadow: 0 20px 25px -5px rgba(0, 0, 0, 0.1);
}

.custom-modal h4 {
  margin-top: 0;
  font-weight: 700;
  color: #1e293b;
}

@keyframes fadeIn {
  from { opacity: 0; }
  to { opacity: 1; }
}

sp_widget.script:
(function() {
    var userId = gs.getUserID();

    /* rejection */
    if (input && input.action) {
        var appGr = new GlideRecord('sysapproval_approver');
        if (appGr.get(input.targetId)) {
            if (input.action == 'approve') {
                appGr.state = 'approved';
                appGr.update();
            } else if (input.action == 'reject') {
                appGr.state = 'rejected';
                appGr.comments = input.comment; // Store the mandatory comment
                appGr.update();
            }
        }
    }

    /* fetch*/
    data.approvals = [];
    var gr = new GlideRecord('sysapproval_approver');
    gr.addQuery('approver', userId);

    // filter
    if (input && input.filter == 'processed') {
        gr.addQuery('state', 'IN', 'approved,rejected');
    } else {
        gr.addQuery('state', 'requested');
    }

    // serach
    if (input && input.searchQuery) {
        var search = input.searchQuery;
        var orQuery = gr.addQuery('sysapproval.getDisplayValue()', 'CONTAINS', search);
        orQuery.addOrCondition('document_id.getDisplayValue()', 'CONTAINS', search);
    }

    gr.orderByDesc('sys_created_on');
    gr.query();

    while (gr.next()) {
        data.approvals.push({
            sys_id: gr.getUniqueValue(),
            target_id: gr.getValue('sysapproval') || gr.getValue('document_id'),
            table: gr.getValue('source_table'),
            display_name: gr.sysapproval.getDisplayValue() || "Task: " + gr.document_id.getDisplayValue(),
            state: gr.getDisplayValue('state'),
            created: gr.getDisplayValue('sys_created_on'),
            approver: gr.getDisplayValue('approver')
        });
    }
})();
